// Dumb capture: turn one Telegram message into one immutable markdown file.
// No AI, no parsing of planning files. The /command IS the category.
const msg = ($input.first().json.message) || {};
const text = (msg.text || '').trim();
const m = text.match(/^\/(feature|bug|idea|research|todo)\b\s*([\s\S]*)$/i);
const type = m ? m[1].toLowerCase() : 'unknown';
const command = m ? ('/' + type) : '(none)';
const body = (m ? (m[2] || '') : text).trim();
const d = new Date();
const p = (n) => String(n).padStart(2, '0');
const ts = `${d.getUTCFullYear()}${p(d.getUTCMonth()+1)}${p(d.getUTCDate())}T${p(d.getUTCHours())}${p(d.getUTCMinutes())}Z`;
const msgId = msg.message_id || 'na';
const id = `${ts}-${msgId}-${type}`;
const path = `captures/inbox/${id}.md`;
const content = `---\nid: ${id}\ncommand: ${command}\ntype: ${type}\ncaptured: ${d.toISOString()}\nvia: telegram\nmsg_id: ${msgId}\nstatus: new\n---\n\n${body || '(empty capture)'}\n`;
const contentB64 = Buffer.from(content, 'utf8').toString('base64');
return [{ json: { id, path, type, command, body, contentB64, chatId: (msg.chat && msg.chat.id) } }];
